mapper.select:
SELECT *
FROM question
WHERE subject = #{subject}
  AND question_type = #{type}
  AND TRIM(content) = #{content}
  AND TRIM(correct_answer) = #{correctAnswer}
ORDER BY question_id
LIMIT 1

SELECT q.*, pq.paper_id FROM question q INNER JOIN paper_question pq ON q.question_id = pq.question_id WHERE pq.paper_id IN
#{paperId}
ORDER BY pq.paper_id, pq.question_order

SELECT *
FROM question
WHERE 1 = 1

    AND content LIKE CONCAT('%', #{content}, '%')


    AND subject = #{subject}


    AND question_type = #{type}


    AND difficulty = #{difficulty}

ORDER BY question_id
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*)
FROM question
WHERE 1 = 1

    AND content LIKE CONCAT('%', #{content}, '%')


    AND subject = #{subject}


    AND question_type = #{type}


    AND difficulty = #{difficulty}
